1	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
2	
3	import * as THREE from 'three';
4	import { EffectComposer } from 'three/addons/postprocessing/EffectComposer.js';
5	import { OutputPass } from 'three/addons/postprocessing/OutputPass.js';
6	import { RenderPass } from 'three/addons/postprocessing/RenderPass.js';
7	
8	import type { Element } from '@bim-ai/core';
9	
10	import {
11	  OrbitViewpointPersistedHud,
12	  type OrbitViewpointPersistFieldPayload,
13	} from './OrbitViewpointPersistedHud';
14	
15	import { useBimStore } from './state/store';
16	import { useTheme } from './state/useTheme';
17	import {
18	  CameraRig,
19	  classifyHotkey,
20	  classifyPointer,
21	  createCameraRig,
22	  wheelDelta,
23	} from './viewport/cameraRig';
24	import {
25	  liveTokenReader,
26	  resolveViewportPaintBundle,
27	  type ElementCategoryToken,
28	  type ViewportPaintBundle,
29	} from './viewport/materials';
30	import { ViewCube } from './viewport/ViewCube';
31	import { type ViewCubePick } from './viewport/viewCubeAlignment';
32	import { SectionBox } from './viewport/sectionBox';
33	import { WalkController, classifyKey as classifyWalkKey } from './viewport/walkMode';
34	
35	const CATEGORY_FALLBACK_COLOR_HEX = '#cbd5e1';
36	
37	function categoryColorOr(bundle: ViewportPaintBundle | null, cat: ElementCategoryToken): string {
38	  return bundle?.categories[cat]?.color ?? CATEGORY_FALLBACK_COLOR_HEX;
39	}
40	
41	function readToken(name: string, fallback: string): string {
42	  const v = liveTokenReader().read(name);
43	  return v && v.trim().length > 0 ? v : fallback;
44	}
45	
46	/** Resolve a CSS color token to an rgb() string that Three.js can parse.
47	 * CSS Color Level 4 hsl() uses spaces (e.g. "hsl(0 0% 100%)") which
48	 * Three.js does not support — routing through a DOM element forces the
49	 * browser to resolve it to "rgb(r, g, b)". */
50	function readColorToken(name: string, fallback: string): string {
51	  if (typeof document === 'undefined') return fallback;
52	  try {
53	    const el = document.createElement('div');
54	    el.style.display = 'none';
55	    el.style.color = `var(${name}, ${fallback})`;
56	    document.body.appendChild(el);
57	    const resolved = getComputedStyle(el).color;
58	    document.body.removeChild(el);
59	    return resolved || fallback;
60	  } catch {
61	    return fallback;
62	  }
63	}
64	
65	function sunPositionFromAzEl(azimuthDeg: number, elevationDeg: number, radiusM = 80): THREE.Vector3 {
66	  const az = THREE.MathUtils.degToRad(azimuthDeg);
67	  const el = THREE.MathUtils.degToRad(elevationDeg);
68	  return new THREE.Vector3(
69	    radiusM * Math.cos(el) * Math.sin(az),
70	    radiusM * Math.sin(el),
71	    radiusM * Math.cos(el) * Math.cos(az),
72	  );
73	}
74	
75	type Props = {
76	  wsConnected: boolean;
77	  onPersistViewpointField?: (payload: OrbitViewpointPersistFieldPayload) => void | Promise<void>;
78	};
79	
80	function addEdges(
81	  mesh: THREE.Mesh,
82	  thresholdAngleDeg = 15,
83	): THREE.LineSegments {
84	  const color = readToken('--color-foreground', '#1a1a1a');
85	  const edges = new THREE.EdgesGeometry(mesh.geometry, thresholdAngleDeg);
86	  const mat = new THREE.LineBasicMaterial({ color, linewidth: 1 });
87	  const lines = new THREE.LineSegments(edges, mat);
88	  lines.renderOrder = 1;
89	  lines.castShadow = false;
90	  lines.receiveShadow = false;
91	  mesh.add(lines);
92	  return lines;
93	}
94	
95	type WallElem = Extract<Element, { kind: 'wall' }>;
96	
97	/** Footprints use world XZ with z ← plan yMm */
98	
99	function xzBoundsMm(poly: Array<{ xMm: number; yMm: number }>): {
100	  minX: number;
101	  maxX: number;
102	  minZ: number;
103	  maxZ: number;
104	  cx: number;
105	  cz: number;
106	  spanX: number;
107	  spanZ: number;
108	} {
109	  let minX = Number.POSITIVE_INFINITY;
110	  let maxX = Number.NEGATIVE_INFINITY;
111	  let minZ = Number.POSITIVE_INFINITY;
112	  let maxZ = Number.NEGATIVE_INFINITY;
113	  for (const p of poly) {
114	    minX = Math.min(minX, p.xMm);
115	
116	    maxX = Math.max(maxX, p.xMm);
117	
118	    minZ = Math.min(minZ, p.yMm);
119	
120	    maxZ = Math.max(maxZ, p.yMm);
121	  }
122	
123	  const spanX = Math.max(maxX - minX, 1);
124	
125	  const spanZ = Math.max(maxZ - minZ, 1);
126	
127	  return {
128	    minX,
129	
130	    maxX,
131	
132	    minZ,
133	
134	    maxZ,
135	
136	    cx: (minX + maxX) / 2,
137	
138	    cz: (minZ + maxZ) / 2,
139	
140	    spanX,
141	
142	    spanZ,
143	  };
144	}
145	
146	function elevationMForLevel(levelId: string, elementsById: Record<string, Element>): number {
147	  const lvl = elementsById[levelId];
148	  if (!lvl || lvl.kind !== 'level') return 0;
149	  return lvl.elevationMm / 1000;
150	}
151	
152	function hostedXZ(
153	  hosted: Extract<Element, { kind: 'door' } | { kind: 'window' }>,
154	  wall: WallElem,
155	): { px: number; pz: number } {
156	  const sx = wall.start.xMm / 1000;
157	  const sz = wall.start.yMm / 1000;
158	  const dx = wall.end.xMm / 1000 - sx;
159	  const dz = wall.end.yMm / 1000 - sz;
160	  const len = Math.max(1e-6, Math.hypot(dx, dz));
161	  const ux = dx / len;
162	  const uz = dz / len;
163	  return {
164	    px: sx + ux * hosted.alongT * len,
165	    pz: sz + uz * hosted.alongT * len,
166	  };
167	}
168	
169	function wallYaw(wall: WallElem) {
170	  const sx = wall.start.xMm / 1000;
171	  const sz = wall.start.yMm / 1000;
172	  const ex = wall.end.xMm / 1000;
173	  const ez = wall.end.yMm / 1000;
174	  return Math.atan2(ez - sz, ex - sx);
175	}
176	
177	function makeFloorSlabMesh(
178	  floor: Extract<Element, { kind: 'floor' }>,
179	  elementsById: Record<string, Element>,
180	  paint: ViewportPaintBundle | null,
181	): THREE.Mesh {
182	  const elev = elevationMForLevel(floor.levelId, elementsById);
183	  const th = THREE.MathUtils.clamp(floor.thicknessMm / 1000, 0.05, 1.8);
184	  const boundary = floor.boundaryMm ?? [];
185	
186	  // Build shape in shape-XY (plan X→shape X, plan Y negated→shape Y).
187	  // After ExtrudeGeometry + rotateX(-π/2): shape X→world X, extrude depth→world Y, −shapeY→world Z.
188	  const shape = new THREE.Shape(
189	    boundary.length >= 3
190	      ? boundary.map((p) => new THREE.Vector2(p.xMm / 1000, -p.yMm / 1000))
191	      : [
192	          new THREE.Vector2(0, 0),
193	          new THREE.Vector2(6, 0),
194	          new THREE.Vector2(6, -6),
195	          new THREE.Vector2(0, -6),
196	        ],
197	  );
198	
199	  // Punch holes for any slab openings hosted by this floor.
200	  for (const el of Object.values(elementsById)) {
201	    if (el.kind !== 'slab_opening' || el.hostFloorId !== floor.id) continue;
202	    const hPts = el.boundaryMm ?? [];
203	    if (hPts.length < 3) continue;
204	    shape.holes.push(
205	      new THREE.Path(hPts.map((p) => new THREE.Vector2(p.xMm / 1000, -p.yMm / 1000))),
206	    );
207	  }
208	
209	  const geom = new THREE.ExtrudeGeometry(shape, { depth: th, bevelEnabled: false });
210	  geom.rotateX(-Math.PI / 2);
211	
212	  const mesh = new THREE.Mesh(
213	    geom,
214	    new THREE.MeshStandardMaterial({
215	      color: categoryColorOr(paint, 'floor'),
216	      roughness: paint?.categories.floor.roughness ?? 0.9,
217	      transparent: true,
218	      opacity: 0.92,
219	    }),
220	  );
221	  mesh.position.set(0, elev, 0);
222	  mesh.userData.bimPickId = floor.id;
223	  addEdges(mesh, 20);
224	  return mesh;
225	}
226	
227	function makeRoofMassMesh(
228	  roof: Extract<Element, { kind: 'roof' }>,
229	  elementsById: Record<string, Element>,
230	  paint: ViewportPaintBundle | null,
231	): THREE.Mesh {
232	  const b = xzBoundsMm(roof.footprintMm ?? []);
233	
234	  const ov = THREE.MathUtils.clamp((roof.overhangMm ?? 0) / 1000, 0, 5);
235	
236	  const refElev = elevationMForLevel(roof.referenceLevelId, elementsById);
237	  // Eave plate = top of the tallest wall at the reference level.
238	  // Without this, the box proxy sits inside the upper-storey walls and is invisible.
239	  const wallsAtRefLevel = Object.values(elementsById).filter(
240	    (e): e is WallElem => e.kind === 'wall' && (e as WallElem).levelId === roof.referenceLevelId,
241	  );
242	  const wallTopM =
243	    wallsAtRefLevel.length > 0
244	      ? Math.max(...wallsAtRefLevel.map((w) => (w.heightMm ?? 0) / 1000))
245	      : 0;
246	  const eaveY = refElev + wallTopM;
247	
248	  const slopeRad = (THREE.MathUtils.clamp(Number(roof.slopeDeg ?? 25), 5, 70) * Math.PI) / 180;
249	  const spanXm = b.spanX / 1000;
250	  const spanZm = b.spanZ / 1000;
251	  const halfSpan = Math.min(spanXm, spanZm) / 2;
252	  const ridgeY = eaveY + halfSpan * Math.tan(slopeRad);
253	
254	  const ox0 = b.minX / 1000 - ov;
255	  const ox1 = b.maxX / 1000 + ov;
256	  const oz0 = b.minZ / 1000 - ov;
257	  const oz1 = b.maxZ / 1000 + ov;
258	
259	  // Triangulated gable mesh — ridge runs along the longer plan axis.
260	  let positions: number[];
261	  if (spanXm >= spanZm) {
262	    // Ridge east-west (along X); slopes drop to south (oz0) and north (oz1).
263	    const rz = (oz0 + oz1) / 2;
264	    positions = [
265	      // South slope
266	      ox0, eaveY, oz0,  ox1, eaveY, oz0,  ox0, ridgeY, rz,
267	      ox1, eaveY, oz0,  ox1, ridgeY, rz,  ox0, ridgeY, rz,
268	      // North slope
269	      ox0, ridgeY, rz,  ox1, ridgeY, rz,  ox0, eaveY, oz1,
270	      ox1, ridgeY, rz,  ox1, eaveY, oz1,  ox0, eaveY, oz1,
271	      // West gable
272	      ox0, eaveY, oz0,  ox0, ridgeY, rz,  ox0, eaveY, oz1,
273	      // East gable
274	      ox1, eaveY, oz0,  ox1, eaveY, oz1,  ox1, ridgeY, rz,
275	    ];
276	  } else {
277	    // Ridge north-south (along Z); slopes drop to west (ox0) and east (ox1).
278	    const rx = (ox0 + ox1) / 2;
279	    positions = [
280	      // West slope
281	      ox0, eaveY, oz0,  ox0, eaveY, oz1,  rx, ridgeY, oz0,
282	      ox0, eaveY, oz1,  rx, ridgeY, oz1,  rx, ridgeY, oz0,
283	      // East slope
284	      rx, ridgeY, oz0,  rx, ridgeY, oz1,  ox1, eaveY, oz0,
285	      rx, ridgeY, oz1,  ox1, eaveY, oz1,  ox1, eaveY, oz0,
286	      // South gable
287	      ox0, eaveY, oz0,  rx, ridgeY, oz0,  ox1, eaveY, oz0,
288	      // North gable
289	      ox0, eaveY, oz1,  ox1, eaveY, oz1,  rx, ridgeY, oz1,
290	    ];
291	  }
292	
293	  const geom = new THREE.BufferGeometry();
294	  geom.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
295	  geom.computeVertexNormals();
296	
297	  const mesh = new THREE.Mesh(
298	    geom,
299	    new THREE.MeshStandardMaterial({
300	      color: categoryColorOr(paint, 'roof'),
301	      transparent: true,
302	      opacity: 0.94,
303	      roughness: paint?.categories.roof.roughness ?? 0.74,
304	      metalness: 0.04,
305	      side: THREE.DoubleSide,
306	    }),
307	  );
308	  mesh.userData.bimPickId = roof.id;
309	  addEdges(mesh);
310	  return mesh;
311	}
