313	function makeStairVolumeMesh(
314	  stair: Extract<Element, { kind: 'stair' }>,
315	  elementsById: Record<string, Element>,
316	  paint: ViewportPaintBundle | null,
317	  selectedId?: string,
318	): THREE.Mesh {
319	  const sx = stair.runStartMm.xMm / 1000;
320	
321	  const sz = stair.runStartMm.yMm / 1000;
322	
323	  const ex = stair.runEndMm.xMm / 1000;
324	
325	  const ez = stair.runEndMm.yMm / 1000;
326	
327	  const dx = ex - sx;
328	
329	  const dz = ez - sz;
330	
331	  const len = Math.max(1e-3, Math.hypot(dx, dz));
332	
333	  const width = THREE.MathUtils.clamp(stair.widthMm / 1000, 0.3, 4);
334	
335	  const bl = elementsById[stair.baseLevelId];
336	
337	  const tl = elementsById[stair.topLevelId];
338	
339	  const riseMm =
340	    bl?.kind === 'level' && tl?.kind === 'level'
341	      ? Math.abs(tl.elevationMm - bl.elevationMm)
342	      : stair.riserMm * 16;
343	
344	  const rise = THREE.MathUtils.clamp(riseMm / 1000, 0.5, 12);
345	
346	  const elevBase = elevationMForLevel(stair.baseLevelId, elementsById);
347	
348	  const mesh = new THREE.Mesh(
349	    new THREE.BoxGeometry(len, rise, width),
350	
351	    new THREE.MeshStandardMaterial({
352	      color:
353	        stair.id === selectedId
354	          ? (paint?.selection.selectedColor ?? '#fcd34d')
355	          : categoryColorOr(paint, 'stair'),
356	    }),
357	  );
358	
359	  mesh.position.set(sx + dx / 2, elevBase + rise / 2, sz + dz / 2);
360	
361	  mesh.rotation.y = Math.atan2(dx, dz);
362	
363	  mesh.userData.bimPickId = stair.id;
