475	function makeRailingMesh(
476	  railing: Extract<Element, { kind: 'railing' }>,
477	  elementsById: Record<string, Element>,
478	  paint: ViewportPaintBundle | null,
479	): THREE.Group {
480	  const group = new THREE.Group();
481	  group.userData.bimPickId = railing.id;
482	
483	  const guardH = THREE.MathUtils.clamp((railing.guardHeightMm ?? 1050) / 1000, 0.5, 2.2);
484	  const pts = railing.pathMm ?? [];
485	  if (pts.length < 2) return group;
486	
487	  const stair = railing.hostedStairId ? elementsById[railing.hostedStairId] : null;
488	  const baseElev =
489	    stair?.kind === 'stair' ? elevationMForLevel(stair.baseLevelId, elementsById) : 0;
490	  const topElev =
491	    stair?.kind === 'stair' ? elevationMForLevel(stair.topLevelId, elementsById) : baseElev;
492	
493	  let totalPlanLen = 0;
494	  for (let i = 1; i < pts.length; i++) {
495	    totalPlanLen += Math.hypot(
496	      (pts[i]!.xMm - pts[i - 1]!.xMm) / 1000,
497	      (pts[i]!.yMm - pts[i - 1]!.yMm) / 1000,
498	    );
499	  }
500	
501	  const mat = new THREE.MeshStandardMaterial({
502	    color: categoryColorOr(paint, 'railing'),
503	    roughness: paint?.categories.railing.roughness ?? 0.6,
504	    metalness: paint?.categories.railing.metalness ?? 0.3,
505	  });
506	
507	  let cumLen = 0;
508	  for (let i = 0; i < pts.length - 1; i++) {
509	    const a = pts[i]!;
510	    const b = pts[i + 1]!;
511	    const ax = a.xMm / 1000,
512	      az = a.yMm / 1000;
513	    const bx = b.xMm / 1000,
514	      bz = b.yMm / 1000;
515	    const planSeg = Math.max(0.001, Math.hypot(bx - ax, bz - az));
516	    const tA = totalPlanLen > 0 ? cumLen / totalPlanLen : 0;
517	    cumLen += planSeg;
518	    const tB = totalPlanLen > 0 ? cumLen / totalPlanLen : 1;
519	    const elevA = baseElev + tA * (topElev - baseElev) + guardH;
520	    const elevB = baseElev + tB * (topElev - baseElev) + guardH;
521	    const riseY = elevB - elevA;
522	
523	    const railLen = Math.sqrt(planSeg * planSeg + riseY * riseY);
524	    const rail = new THREE.Mesh(new THREE.BoxGeometry(railLen, 0.05, 0.05), mat);
525	    rail.position.set((ax + bx) / 2, (elevA + elevB) / 2, (az + bz) / 2);
526	    const dir = new THREE.Vector3(bx - ax, riseY, bz - az).normalize();
527	    rail.quaternion.setFromUnitVectors(new THREE.Vector3(1, 0, 0), dir);
528	    addEdges(rail);
529	    group.add(rail);
530	  }
531	
532	  return group;
533	}
