613	function aabbWireframeVertices(
614	  min: { x: number; y: number; z: number },
615	  max: { x: number; y: number; z: number },
616	): THREE.Vector3[] {
617	  const v = (x: number, y: number, z: number): THREE.Vector3 => new THREE.Vector3(x, y, z);
618	  const c000 = v(min.x, min.y, min.z);
619	  const c100 = v(max.x, min.y, min.z);
620	  const c010 = v(min.x, max.y, min.z);
621	  const c110 = v(max.x, max.y, min.z);
622	  const c001 = v(min.x, min.y, max.z);
623	  const c101 = v(max.x, min.y, max.z);
624	  const c011 = v(min.x, max.y, max.z);
625	  const c111 = v(max.x, max.y, max.z);
626	  // 12 edges as vertex pairs.
627	  return [
628	    c000,
629	    c100,
630	    c100,
631	    c110,
632	    c110,
633	    c010,
634	    c010,
635	    c000,
636	    c001,
637	    c101,
638	    c101,
639	    c111,
640	    c111,
641	    c011,
642	    c011,
643	    c001,
644	    c000,
645	    c001,
646	    c100,
647	    c101,
648	    c110,
649	    c111,
650	    c010,
651	    c011,
652	  ];
653	}
