655	function applyClippingPlanesToMeshes(root: THREE.Object3D, planes: THREE.Plane[]) {
656	  if (!planes.length) return;
657	  root.traverse((node) => {
658	    const mesh = node as THREE.Mesh;
659	    if (mesh.isMesh && mesh.material instanceof THREE.MeshStandardMaterial) {
660	      const m = mesh.material.clone();
661	      m.clippingPlanes = planes.slice();
662	      mesh.material = m;
663	    }
664	  });
665	}
